\begin{definition}
[Restriction of module sheaves along an open immersion]
  \label{lem:modules_restrict_functor_mathlib}
  \lean{AlgebraicGeometry.Scheme.Modules.restrictFunctor}
  \mathlibok
  \textit{Provided by Mathlib
  (\texttt{Mathlib.AlgebraicGeometry.Modules.Sheaf}).}
  For an open immersion \(f : X \to Y\) of schemes, Mathlib provides the restriction
  functor \(Y.\mathrm{Modules} \to X.\mathrm{Modules}\) on module sheaves, with sections
  \(\Gamma(M\!\restriction\! f, V) = \Gamma(M, f(V))\). Specialized to the inclusion \(j
  : U \hookrightarrow X\) of an open subscheme, this is the restriction \(\mathcal{F}
  \mapsto \mathcal{F}|_U\) used in Definition~\ref{def:absolute_cohomology}.
\end{definition}

